import GlassPanel from './GlassPanel';
import { tokens } from '../../styles/tokens';

/**
 * StatCard - Reusable metric tile for P&L, bot stats, portfolio metrics, etc.
 *
 * Props:
 *   label     - Top label text (e.g. "Day P&L", "Positions")
 *   value     - Main display value (e.g. "+$1,234.56", "12")
 *   subtitle  - Optional bottom subtitle (e.g. "(+2.34%)")
 *   icon      - Optional icon element (rendered top-right)
 *   trend     - 'up' | 'down' | 'neutral' | null
 *   color     - Override value color (default: text primary)
 *   accentColor - Top accent bar gradient color
 *   onClick   - Click handler
 *   compact   - Smaller padding for dense grids
 *   style     - Additional inline styles on wrapper
 *   className - Additional CSS classes
 */
export default function StatCard({
  label,
  value,
  subtitle,
  icon,
  trend,
  color,
  accentColor,
  onClick,
  compact = false,
  style,
  className,
}) {
  const trendArrow = trend === 'up' ? '\u25B2' : trend === 'down' ? '\u25BC' : null;
  const trendColor = trend === 'up' ? tokens.color.green : trend === 'down' ? tokens.color.red : tokens.color.textSecondary;
  const valueColor = color || (trend === 'up' ? tokens.color.green : trend === 'down' ? tokens.color.red : tokens.color.text);
  const accent = accentColor || (trend === 'up' ? tokens.color.green : trend === 'down' ? tokens.color.red : tokens.color.blue);

  return (
    <GlassPanel
      hover={!!onClick}
      onClick={onClick}
      padding={compact ? `${tokens.spacing.md}px ${tokens.spacing.md}px ${tokens.spacing.sm}px` : `${tokens.spacing.lg}px ${tokens.spacing.lg}px ${tokens.spacing.md}px`}
      className={className}
      style={{
        display: 'flex',
        flexDirection: 'column',
        gap: compact ? 4 : 6,
        position: 'relative',
        overflow: 'hidden',
        ...style,
      }}
    >
      {/* Top accent bar */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: tokens.spacing.md,
        right: tokens.spacing.md,
        height: 2,
        background: `linear-gradient(90deg, ${accent}, ${accent}80)`,
        borderRadius: 1,
      }} />

      {/* Label row */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
      }}>
        <span style={{
          fontFamily: tokens.font.sans,
          fontSize: compact ? tokens.fontSize.xs : tokens.fontSize.sm,
          fontWeight: tokens.fontWeight.semibold,
          color: tokens.color.textSecondary,
          textTransform: 'uppercase',
          letterSpacing: '0.06em',
        }}>
          {label}
        </span>
        {icon && (
          <span style={{
            color: tokens.color.textMuted,
            fontSize: compact ? 14 : 16,
            lineHeight: 1,
          }}>
            {icon}
          </span>
        )}
      </div>

      {/* Value row */}
      <div style={{
        display: 'flex',
        alignItems: 'baseline',
        gap: 6,
      }}>
        {trendArrow && (
          <span style={{
            fontFamily: tokens.font.mono,
            fontSize: compact ? 10 : 12,
            color: trendColor,
          }}>
            {trendArrow}
          </span>
        )}
        <span style={{
          fontFamily: tokens.font.mono,
          fontSize: compact ? tokens.fontSize.lg : tokens.fontSize.xl,
          fontWeight: tokens.fontWeight.bold,
          fontVariantNumeric: 'tabular-nums',
          color: valueColor,
          lineHeight: 1.2,
        }}>
          {String(value ?? '\u2014')}
        </span>
      </div>

      {/* Subtitle */}
      {subtitle && (
        <span style={{
          fontFamily: tokens.font.mono,
          fontSize: compact ? tokens.fontSize.xs : tokens.fontSize.sm,
          color: tokens.color.textSecondary,
          lineHeight: 1.2,
        }}>
          {subtitle}
        </span>
      )}
    </GlassPanel>
  );
}
